import React, { useEffect, useState } from "react";
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
} from "chart.js";
import { Doughnut, Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const response = await fetch("/api/dashboard-stats");
        const data = await response.json();
        setStats(data);
      } catch (err) {
        console.error("Error fetching dashboard stats:", err);
      }
    };
    fetchStats();
  }, []);

  if (!stats) return <div className="loading">Loading dashboard data...</div>;

  const donutOptions = {
    cutout: "75%",
    plugins: {
      tooltip: { enabled: true },
      legend: { display: false },
    },
  };

  const renderSmallDonut = (label, value, color) => ({
    data: {
      labels: [label, ""],
      datasets: [
        {
          data: [value, 100 - value],
          backgroundColor: [color, "#e0e0e0"],
          borderWidth: 0,
        },
      ],
    },
  });

  // const pieData = {
  //   labels: ["Free", "Occupied"],
  //   datasets: [
  //     {
  //       data: [stats.pieChart.free, stats.pieChart.occupied],
  //       backgroundColor: ["#4CAF50", "#F44336"],
  //       borderWidth: 0,
  //     },
  //   ],
  // };

  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms",
        data: Object.values(stats.barChart),
        backgroundColor: "#2196F3",
        barThickness: 20,
      },
    ],
  };

  return (
    <div className="dashboard-wrapper">
      <h2 className="dashboard-title">Welcome, Rajeshwaran</h2>

      <div className="dashboard-grid">

        {/* Projector Room - Keep Doughnut */}
        <div className="card">
          <h4 className="card-title">Projector Rooms</h4>
          <Doughnut
            data={renderSmallDonut("Projectors", stats.resources.projectorRooms, "#ff9800").data}
            options={donutOptions}
          />
          <div className="donut-center-text">{stats.resources.projectorRooms}</div>
        </div>

        {/* Enhanced: Labs Availability */}
        <div className="card info-tile">
          <h4 className="card-title">Labs Availability</h4>
          <p className="card-subtext">
            {stats.resources.labs} out of {stats.resources.totalLabs || 10} labs available
          </p>
          <div className="progress-bar">
            <div style={{ width: `${(stats.resources.labs / (stats.resources.totalLabs || 10)) * 100}%` }} />
          </div>
          <span className="status-badge success">Healthy</span>
        </div>

        {/* Enhanced: Classrooms Available */}
        <div className="card info-tile">
          <h4 className="card-title">Classrooms Available</h4>
          <p className="card-subtext">
            {stats.resources.classrooms} classrooms free
          </p>
          <div className="progress-bar">
            <div style={{ width: `${(stats.resources.classrooms / stats.resources.totalRooms) * 100}%` }} />
          </div>
          <span className="status-badge info">Operational</span>
        </div>

        {/* Enhanced: Room Occupancy */}
        <div className="card info-tile">
          <h4 className="card-title">Room Occupancy</h4>
          <p className="card-subtext">
            {stats.pieChart.occupied} rooms occupied / {stats.resources.totalRooms}
          </p>
          <div className="progress-bar danger">
            <div style={{ width: `${(stats.pieChart.occupied / stats.resources.totalRooms) * 100}%` }} />
          </div>
          <span className="status-badge danger">
            {((stats.pieChart.occupied / stats.resources.totalRooms) * 100).toFixed(0)}% occupied
          </span>
        </div>

        {/* Optional: Room Free Calculation - still donut */}
        <div className="card">
          <h4 className="card-title">Not Occupied</h4>
          <Doughnut
            data={renderSmallDonut(
              "Available",
              stats.resources.totalRooms - stats.pieChart.occupied,
              "#009688"
            ).data}
            options={donutOptions}
          />
          <div className="donut-center-text">
            {stats.resources.totalRooms - stats.pieChart.occupied}
          </div>
        </div>

        {/* Bar Chart */}
        <div className="card full">
          <h3 className="card-heading">Free Rooms per Weekday</h3>
          <Bar
            data={barData}
            options={{
              responsive: true,
              plugins: { legend: { display: false } },
              scales: { y: { beginAtZero: true } },
            }}
          />
        </div>

        {/* Resource Summary */}
        <div className="card full">
          <h3 className="card-heading">Resource Summary</h3>
          <ul className="resource-summary">
            <li>
              <strong>Total Rooms:</strong> {stats.resources.totalRooms}
            </li>
            <li>
              <strong>Labs:</strong> {stats.resources.labs} / {stats.resources.totalRooms}
              <div className="progress-bar">
                <div
                  style={{
                    width: `${(stats.resources.labs / stats.resources.totalRooms) * 100}%`,
                  }}
                />
              </div>
            </li>
            <li>
              <strong>Projector Rooms:</strong> {stats.resources.projectorRooms}
            </li>
            <li>
              <strong>Classrooms:</strong> {stats.resources.classrooms}
            </li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
